func BindRenderbuffer(target uint32, renderbuffer uint32) { gpBindRenderbuffer(target, renderbuffer) }
func BindSampler(unit uint32, sampler uint32) { gpBindSampler(unit, sampler) }
func BindSamplers(first uint32, count int32, samplers *uint32) { gpBindSamplers(first, count, samplers) }
